
INSERT INTO t_p51929753_pension_audit_portal.tab_content (tab_id, title, subtitle, description, conditions, mistakes, badge)
VALUES
('zhkh', 'Проверка начислений по ЖКХ', 'Аудит квитанций и тарифов', 
 'Управляющие компании и ресурсоснабжающие организации нередко допускают ошибки в начислениях — применяют неверные тарифы, начисляют лишние услуги или не учитывают льготы. Мы проверяем каждую строку квитанции.',
 '["Проверка правильности применения тарифов на все виды коммунальных услуг","Контроль корректности начислений за отопление, ГВС, ХВС, электроэнергию","Проверка начислений за содержание и ремонт общего имущества","Анализ применения льгот и субсидий — все ли скидки учтены","Проверка задолженности: законность пеней и штрафов","Сравнение нормативного и фактического потребления при отсутствии счётчика"]',
 '["УК применяет тариф прошлого периода без уведомления жильцов","Площадь квартиры указана неверно — завышены все объёмы начислений","Льготы пенсионера или инвалида не применены автоматически","Повторное начисление за уже оплаченные периоды","Некорректный расчёт ОДН (общедомовых нужд)"]',
 'Аудит квитанций ЖКХ'),
('contracts', 'Проверка договоров и документов', 'Юридический анализ перед подписанием',
 'Договор аренды, купли-продажи, оказания услуг, трудовой договор — каждый документ содержит условия, которые могут ущемлять ваши права. Мы анализируем текст и выявляем скрытые риски до подписания.',
 '["Договоры купли-продажи недвижимости и транспорта","Договоры аренды жилых и нежилых помещений","Трудовые договоры и дополнительные соглашения","Договоры оказания услуг, подряда, займа","Кредитные договоры и договоры с МФО","Наследственные документы, завещания, дарственные"]',
 '["Скрытые штрафные санкции в теле договора мелким шрифтом","Односторонний порядок изменения условий в пользу компании","Отсутствие ответственности исполнителя за нарушение сроков","Незаконные условия об ограничении прав потребителя","Неверно указанные реквизиты сторон — договор может быть признан недействительным"]',
 'Юридический аудит'),
('svo', 'Участникам СВО', 'Выплаты, льготы и документы',
 'Военнослужащие, участники специальной военной операции и члены их семей имеют право на широкий спектр выплат и льгот. Мы помогаем собрать документы, оформить заявления и получить все положенные по закону средства.',
 '["Единовременная выплата при ранении (лёгкое — 3 млн ₽, тяжёлое — от 3 до 5 млн ₽)","Страховые выплаты по линии Росгвардии и МО РФ при травмах и заболеваниях","Региональные выплаты — размер зависит от субъекта РФ, можно получить от 1 до 5 млн ₽","Выплаты семьям погибших — 5 млн ₽ федеральных + региональные","Надбавки и доплаты за государственные награды (ордена, медали)","Льготы на ЖКХ, транспортный налог, имущественный налог для ветеранов боевых действий"]',
 '["Неверно оформлена справка о ранении — отказ в страховой выплате","Региональная выплата не получена из-за отсутствия заявления в нужный орган","Награды не учтены при расчёте пенсии или надбавок","Военно-врачебная комиссия занизила степень тяжести ранения","Семья не оформила статус членов семьи погибшего военнослужащего"]',
 'СВО: выплаты и льготы')
